    async function setXMinVariableSelection(mode) {
      const win = frames.xmin?.contentWindow;
      if (!win || typeof win.eval !== 'function') return;
      await ensureXMinNoneModeSupport();
      await ensureXMinManualCurveSupport();
      await setXMinCurveDrawState(false, { render:false });
      const bridgeButtons = Array.from(document.querySelectorAll('#bridgeXminVariableList .bridge-list-btn'));
      const visibleLabels = bridgeButtons.map(btn => String(btn.textContent || '').trim()).filter(label => label && label.toUpperCase() !== 'ALL');
      unifiedState.xminVariableNoneMode = mode === 'none';
      try {
        const payloadMode = JSON.stringify(mode);
        const payloadLabels = JSON.stringify(visibleLabels);
        win.eval(`(function(mode, labels){
          try {
            window.__bridgeXminNoneMode = mode === 'none';
            if (mode === 'all') selectedVars = new Set((labels || []).filter(Boolean));
            else if (mode === 'none') selectedVars = new Set();
            else selectedVars = new Set((labels || []).filter(Boolean));
            if (typeof populateVariableList === 'function') populateVariableList();
            if (typeof applyFilters === 'function') applyFilters();
            if (typeof buildTable === 'function') buildTable();
            if (typeof updateChart === 'function') updateChart();
            if (typeof window.__bridgeApplyXminNoneMode === 'function') window.__bridgeApplyXminNoneMode(mode === 'none');
          } catch (err) {
            console.error(err);
          }
        })(${payloadMode}, ${payloadLabels})`);
      } catch (err) {
        console.warn(err);
      }
      setTimeout(() => {
        syncXMinVariableBridge();
        renderUnifiedReport();
      }, 120);
    }

    function syncAWSCategoryBridge() {
      const container = document.getElementById('bridgeAwsCategoryList');
      const doc = frames.aws?.contentDocument;
      const source = doc?.getElementById('category-filters');
      if (!container) return;
      if (!source) {
        setBridgeEmpty(container, 'Load and process the AWS file to show category filters.');
        return;
      }
      const liveRows = Array.from(source.querySelectorAll(':scope > .category-item'));
      const items = liveRows.map((row, index) => {
        const checkbox = row.querySelector('input[type="checkbox"]');
        const labelNode = row.querySelector('label, span');
        return {
          index,
          checked: !!checkbox?.checked,
          label: bridgeText(labelNode || row)
        };
      }).filter(item => item.label);
      const state = JSON.stringify(items);
      if (container.dataset.state === state) return;
      container.dataset.state = state;
      container.dataset.emptyMessage = '';
      container.innerHTML = '';
      if (!items.length) {
        setBridgeEmpty(container, 'No AWS categories are available for the current file.');
        return;
      }
      items.forEach(item => {
        const label = document.createElement('label');
        label.className = 'bridge-check-item';
        const input = document.createElement('input');
        input.type = 'checkbox';
        input.checked = item.checked;
        const span = document.createElement('span');
        span.textContent = item.label;
        input.addEventListener('change', () => {
          const currentRows = Array.from(source.querySelectorAll(':scope > .category-item'));
          const liveCheckbox = currentRows[item.index]?.querySelector('input[type="checkbox"]');
          if (!liveCheckbox) return;
          liveCheckbox.checked = input.checked;
          liveCheckbox.dispatchEvent(new Event('change', { bubbles:true }));
          scheduleUnifiedSidebarSync(80);
        });
        label.append(input, span);
        container.appendChild(label);
      });
    }

