    function debounce(fn, wait = 120) {
      let timer = null;
      return function(...args) {
        clearTimeout(timer);
        timer = setTimeout(() => fn.apply(this, args), wait);
      };
    }

    let unifiedSidebarSyncTimer = null;
    let unifiedSidebarSyncRunning = false;
    let unifiedSidebarSyncQueued = false;
    let unifiedSidebarSyncLoopStarted = false;

    function runUnifiedSidebarSync() {
      if (unifiedSidebarSyncRunning) {
        unifiedSidebarSyncQueued = true;
        return;
      }
      unifiedSidebarSyncRunning = true;
      try {
        syncUnifiedTurbineBridge();
        syncAWSCategoryBridge();
        syncAWSEventBridge();
        syncXMinCategoryBridge();
        syncXMinIntervalBridge();
        syncXMinVariableBridge();
      } finally {
        unifiedSidebarSyncRunning = false;
        if (unifiedSidebarSyncQueued) {
          unifiedSidebarSyncQueued = false;
          requestAnimationFrame(runUnifiedSidebarSync);
        }
      }
    }

    function syncUnifiedSidebarBridges() {
      runUnifiedSidebarSync();
    }

    function scheduleUnifiedSidebarSync(delay = 80) {
      clearTimeout(unifiedSidebarSyncTimer);
      unifiedSidebarSyncTimer = setTimeout(runUnifiedSidebarSync, Math.max(0, delay));
    }

    function startUnifiedSidebarSyncLoop() {
      if (unifiedSidebarSyncLoopStarted) return;
      unifiedSidebarSyncLoopStarted = true;
      const tick = () => {
        scheduleUnifiedSidebarSync(0);
        setTimeout(tick, document.hidden ? 7000 : 4500);
      };
      document.addEventListener('visibilitychange', () => {
        if (!document.hidden) scheduleUnifiedSidebarSync(120);
      }, { passive:true });
      tick();
    }

