/* ===== Original script block 9: id="v25-upload-center-integrate-script" ===== */

(function(){
  function integrateUploadCenterStatus() {
    const controls = document.getElementById('unified-controls');
    const main = controls?.querySelector('.upload-hub-main');
    const summary = controls?.querySelector('.upload-summary-badges');
    const sideStack = controls?.querySelector('.upload-side-stack');
    if (!controls || !main || !summary || !sideStack) return;

    const cards = Array.from(sideStack.querySelectorAll(':scope > .upload-side-card'));
    const pipelineCard = cards.find(card => /pipeline status/i.test(card.textContent || ''));
    const selectedFilesCard = cards.find(card => /selected files/i.test(card.textContent || ''));

    if (selectedFilesCard) selectedFilesCard.remove();

    if (pipelineCard && !pipelineCard.classList.contains('upload-integrated-status')) {
      pipelineCard.classList.add('upload-integrated-status');
      summary.insertAdjacentElement('afterend', pipelineCard);
    }

    if (!sideStack.children.length) {
      sideStack.remove();
    }
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', integrateUploadCenterStatus);
  } else {
    integrateUploadCenterStatus();
  }
})();

